import{_ as d,o as r,c as a,a2 as e}from"./chunks/framework.ZhLefgN8.js";const u=JSON.parse('{"title":"App 设置","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"app-guide/settings.md","filePath":"zh-CN/app-guide/settings.md"}'),h={name:"app-guide/settings.md"};function o(l,t,i,n,b,s){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="app-设置" tabindex="-1">App 设置 <a class="header-anchor" href="#app-设置" aria-label="Permalink to &quot;App 设置&quot;">​</a></h1><p>设置是 App 的全局配置中心，提供账号安全、交易偏好、通知、隐私等各类个性化配置项。</p><h2 id="页面入口" tabindex="-1">页面入口 <a class="header-anchor" href="#页面入口" aria-label="Permalink to &quot;页面入口&quot;">​</a></h2><p>「我的」→「设置」</p><h2 id="通用" tabindex="-1">通用 <a class="header-anchor" href="#通用" aria-label="Permalink to &quot;通用&quot;">​</a></h2><table tabindex="0"><thead><tr><th>设置项</th><th>说明</th></tr></thead><tbody><tr><td>皮肤设置</td><td>选择 App 显示主题（如经典黑）</td></tr><tr><td>语言设置</td><td>切换 App 界面语言</td></tr><tr><td>屏幕常亮</td><td>开启后屏幕不自动熄灭</td></tr><tr><td>截屏快捷分享</td><td>截屏后快速分享</td></tr><tr><td>自动下载最新安装包</td><td>仅 Wi-Fi 网络下自动下载更新包</td></tr><tr><td>辅助功能</td><td>无障碍相关设置</td></tr><tr><td>切换接入点</td><td>切换服务器接入节点</td></tr><tr><td>网络诊断</td><td>检测当前网络连接状态</td></tr><tr><td>清理缓存</td><td>显示当前缓存大小，点击清理</td></tr></tbody></table><h2 id="账号与安全" tabindex="-1">账号与安全 <a class="header-anchor" href="#账号与安全" aria-label="Permalink to &quot;账号与安全&quot;">​</a></h2><p><strong>账号信息：</strong></p><ul><li>登录 ID</li><li>手机号（可修改）</li><li>邮箱（可修改）</li></ul><blockquote><p>修改接收结单、交易通知的手机号/邮箱，需前往「账户设置 → 联系方式」。</p></blockquote><p><strong>第三方账号绑定：</strong></p><ul><li>微信</li><li>支付宝</li></ul><p><strong>安全设置：</strong></p><table tabindex="0"><thead><tr><th>设置项</th><th>说明</th></tr></thead><tbody><tr><td>设备管理</td><td>查看和管理已登录设备</td></tr><tr><td>修改登录密码</td><td>更改账号登录密码</td></tr><tr><td>生物识别登录</td><td>开启指纹或面容 ID 登录</td></tr><tr><td>登录有效时长</td><td>设置登录状态的保持时长（默认 30 天）</td></tr><tr><td>企业员工认证</td><td>认证长桥企业员工身份</td></tr><tr><td>注销账号</td><td>永久注销账号</td></tr></tbody></table><h2 id="账户设置" tabindex="-1">账户设置 <a class="header-anchor" href="#账户设置" aria-label="Permalink to &quot;账户设置&quot;">​</a></h2><p>账户设置针对具体证券账户，支持切换账户分别配置。</p><table tabindex="0"><thead><tr><th>设置项</th><th>说明</th></tr></thead><tbody><tr><td>折算货币</td><td>设置资产总览的折算显示货币（默认 USD）</td></tr><tr><td>修改交易密码</td><td>修改当前账户的交易密码</td></tr><tr><td>交易密码有效时长</td><td>输入一次交易密码后的免输有效期（默认 4 小时）</td></tr><tr><td>指纹 ID</td><td>开启后验证交易密码时可用指纹代替</td></tr><tr><td>结单提醒</td><td>设置结单推送提醒方式</td></tr><tr><td>多重因素验证</td><td>账户二次验证设置</td></tr><tr><td>资产隐私设置</td><td>控制他人是否可查看你的资产信息</td></tr><tr><td>自动还款</td><td>开启后账户存在欠款时自动用其他币种余额兑换还款，避免产生额外融资利息</td></tr><tr><td>联系方式</td><td>设置接收证券类信息的手机号/邮箱，可与登录账号不同</td></tr></tbody></table><h2 id="交易设置" tabindex="-1">交易设置 <a class="header-anchor" href="#交易设置" aria-label="Permalink to &quot;交易设置&quot;">​</a></h2><p><strong>功能设置：</strong></p><table tabindex="0"><thead><tr><th>设置项</th><th>说明</th></tr></thead><tbody><tr><td>快捷下单</td><td>配置快捷交易模式</td></tr><tr><td>下单偏好设置</td><td>配置默认下单参数（数量、有效期等）</td></tr><tr><td>订单查询设置</td><td>订单列表的展示偏好</td></tr><tr><td>下单二次确认</td><td>开启后下单前需额外确认（建议保持开启）</td></tr><tr><td>委托后面板</td><td>下单后是否自动展示委托详情面板</td></tr></tbody></table><p><strong>交易提示开关：</strong></p><table tabindex="0"><thead><tr><th>提示项</th><th>说明</th></tr></thead><tbody><tr><td>交易提醒音效</td><td>委托成功/成交时的提示音</td></tr><tr><td>高买低卖提醒</td><td>下单价格高于买入价或低于卖出价时提醒</td></tr><tr><td>平仓冲突提醒</td><td>下单可能影响持仓平仓时提醒</td></tr><tr><td>市价单交易提醒</td><td>发出市价单前提醒</td></tr><tr><td>最小变动单位提醒</td><td>价格不符合最小变动单位时提醒</td></tr><tr><td>卖空提醒</td><td>卖空操作前提醒</td></tr><tr><td>快捷改单提示</td><td>使用快捷改单时提示</td></tr><tr><td>长期有效订单风险提示</td><td>设置长期有效订单时的风险提示</td></tr><tr><td>OTC 订单延迟行情提醒</td><td>OTC 订单使用延迟行情时提醒</td></tr><tr><td>末日期权交易提示</td><td>交易到期日期权时提示</td></tr><tr><td>非常用货币交易提示</td><td>使用非常用货币交易时提示</td></tr></tbody></table><h2 id="消息设置" tabindex="-1">消息设置 <a class="header-anchor" href="#消息设置" aria-label="Permalink to &quot;消息设置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>设置项</th><th>说明</th></tr></thead><tbody><tr><td>通知开关</td><td>跳转系统通知权限页面开启或关闭推送</td></tr><tr><td>资产与交易</td><td>订单成交、资产变动等交易类通知</td></tr><tr><td>资讯与社区</td><td>行情资讯、社区互动等运营活动通知</td></tr></tbody></table><h2 id="资讯与直播" tabindex="-1">资讯与直播 <a class="header-anchor" href="#资讯与直播" aria-label="Permalink to &quot;资讯与直播&quot;">​</a></h2><table tabindex="0"><thead><tr><th>设置项</th><th>说明</th></tr></thead><tbody><tr><td>自选资讯入口设置</td><td>选择「关注」Tab 中资讯入口默认展示的内容</td></tr><tr><td>直播悬浮窗播放</td><td>退出直播页后以悬浮窗继续播放</td></tr></tbody></table><h2 id="隐私" tabindex="-1">隐私 <a class="header-anchor" href="#隐私" aria-label="Permalink to &quot;隐私&quot;">​</a></h2><table tabindex="0"><thead><tr><th>设置项</th><th>说明</th></tr></thead><tbody><tr><td>个性化推荐</td><td>开启后展示基于行为分析的个性化内容推荐</td></tr><tr><td>公开我关注的股票</td><td>控制他人是否能在你的个人主页看到你关注的股票</td></tr><tr><td>公开我关注的股单</td><td>控制他人是否能在你的个人主页看到你关注的股单</td></tr><tr><td>黑名单</td><td>管理黑名单用户（被拉黑用户无法关注你或与你互动）</td></tr><tr><td>隐私相关文档</td><td>隐私政策、个人信息收集情况、第三方共享清单等</td></tr></tbody></table><h2 id="关于" tabindex="-1">关于 <a class="header-anchor" href="#关于" aria-label="Permalink to &quot;关于&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>说明</th></tr></thead><tbody><tr><td>当前版本</td><td>显示当前安装的 App 版本号</td></tr><tr><td>检查更新</td><td>检测是否有新版本可用</td></tr><tr><td>版本介绍</td><td>查看当前版本更新内容</td></tr><tr><td>关于长桥</td><td>公司介绍页面</td></tr><tr><td>WHO&#39;S LEO</td><td>长桥吉祥物 LEO 介绍</td></tr><tr><td>服务协议</td><td>服务协议全文</td></tr><tr><td>市场行情服务条款</td><td>行情服务相关条款</td></tr></tbody></table><h2 id="其他入口" tabindex="-1">其他入口 <a class="header-anchor" href="#其他入口" aria-label="Permalink to &quot;其他入口&quot;">​</a></h2><ul><li><strong>切换账号</strong> — 退出当前账号并切换到其他账号</li><li><strong>退出登录</strong> — 退出当前账号登录状态</li></ul>',32)])])}const c=d(h,[["render",o]]);export{u as __pageData,c as default};
